def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an artist (or related entities) into a single,
    fluent English sentence. Handles a variety of predicates and joins multiple
    facts with commas and a final conjunction.
    """
    if not triples:
        return ""

    # Group triples by subject for better sentence construction
    subject_facts = {}
    for t in triples:
        if t.subject not in subject_facts:
            subject_facts[t.subject] = []
        subject_facts[t.subject].append(t)

    main_subject = list(subject_facts.keys())[0] if subject_facts else None
    if not main_subject:
        return ""

    # Build phrases for the main subject
    main_phrases = []
    other_facts = []

    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Render predicate to natural language
        if p == "birthDate":
            phrase = f"{s} was born on {o}"
        elif p == "deathDate":
            phrase = f"{s} died on {o}"
        elif p == "birthPlace":
            phrase = f"{s} was born in {o}"
        elif p == "deathPlace":
            phrase = f"{s} died in {o}"
        elif p == "origin":
            phrase = f"{s} originates from {o}"
        elif p == "nationality":
            phrase = f"{s} is a citizen of {o}"
        elif p == "genre":
            phrase = f"{s} performs {o} music"
        elif p == "instrument":
            phrase = f"{s} plays the {o}"
        elif p == "occupation":
            phrase = f"{s} works as a {o}"
        elif p == "associatedBand/associatedMusicalArtist":
            phrase = f"{s} is associated with {o}"
        elif p == "recordLabel":
            phrase = f"{s} is signed to {o}"
        elif p == "activeYearsStartYear":
            phrase = f"{s} started their career in {o}"
        elif p == "activeYearsEndYear":
            phrase = f"{s} ended their career in {o}"
        elif p == "alternativeName":
            phrase = f"{s} is also known as {o}"
        elif p == "capital":
            phrase = f"The capital of {s} is {o}"
        elif p == "country":
            phrase = f"{s} is located in {o}"
        elif p in {"language", "officialLanguage"}:
            phrase = f"{s} uses {o}"
        elif p == "parentCompany":
            phrase = f"{s} is owned by {o}"
        elif p == "bandMember":
            phrase = f"{s} includes member {o}"
        elif p == "leader":
            phrase = f"The leader of {s} is {o}"
        elif p == "leaderTitle":
            phrase = f"The leader title of {s} is {o}"
        elif p == "background":
            phrase = f"{s} has a background as a {o}"
        elif p == "birthYear":
            phrase = f"{s} was born in {o}"
        elif p == "deathPlace":
            phrase = f"{s} died in {o}"
        elif p == "ethnicGroup":
            phrase = f"{s} is part of the {o} ethnic group"
        elif p == "foundingDate":
            phrase = f"{s} was founded on {o}"
        elif p == "isPartOf":
            phrase = f"{s} is part of {o}"
        elif p == "location":
            phrase = f"{s} is located in {o}"
        elif p == "demonym":
            phrase = f"Residents of {s} are called {o}"
        elif p == "currency":
            phrase = f"{s} uses {o} as currency"
        elif p == "anthem":
            phrase = f"{s}'s anthem is {o}"
        elif p == "areaTotal":
            phrase = f"{s} has a total area of {o}"
        elif p == "elevationAboveTheSeaLevel":
            phrase = f"{s} is at an elevation of {o} meters"
        elif p == "postalCode":
            phrase = f"{s} has postal codes {o}"
        elif p == "populationDensity":
            phrase = f"{s} has a population density of {o}"
        elif p == "meaning":
            phrase = f"{s} means {o}"
        elif p == "longName":
            phrase = f"{s}'s long name is {o}"
        elif p == "professionalField":
            phrase = f"{s} works in {o}"
        elif p == "training":
            phrase = f"{s} was trained at {o}"
        elif p == "distributingCompany":
            phrase = f"{s} is distributed by {o}"
        elif p == "musicFusionGenre":
            phrase = f"{s} is a fusion genre of {o}"
        elif p == "musicSubgenre":
            phrase = f"{s} is a subgenre of {o}"
        elif p == "stylisticOrigin":
            phrase = f"{s} has stylistic origins in {o}"
        elif p == "derivative":
            phrase = f"{s} has influenced {o}"
        elif p == "governingBody":
            phrase = f"{s} is governed by {o}"
        elif p == "genre":
            phrase = f"{s} performs {o} music"
        else:
            # Fallback generic rendering
            phrase = f"{s} {p} {o}"

        if s == main_subject:
            main_phrases.append(phrase.rstrip("."))
        else:
            other_facts.append(phrase.rstrip("."))

    # Join phrases into a coherent complex sentence
    all_phrases = main_phrases + other_facts

    if len(all_phrases) == 1:
        return all_phrases[0] + "."
    elif len(all_phrases) == 2:
        return all_phrases[0] + ", and " + all_phrases[1] + "."
    else:
        return ", ".join(all_phrases[:-1]) + ", and " + all_phrases[-1] + "."

